// ── API Client for MAIY Tech Hub Backend ──────────────────────────────────────
// Maps frontend to Fastify + MongoDB backend API

const API_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:4000'
const TIMEOUT = Number(process.env.NEXT_PUBLIC_API_TIMEOUT) || 10000

// ── Types ─────────────────────────────────────────────────────────────────────

export interface ApiArticle {
  _id: string
  slug: string
  title: string
  excerpt: string
  content: string
  category: string
  tags: string[]
  hero?: string | null
  author: string
  readingTime: number
  publishedAt: string
  published: boolean
  createdAt: string
  updatedAt: string
}

export interface ApiArticleSummary {
  _id: string
  slug: string
  title: string
  excerpt: string
  category: string
  tags: string[]
  hero?: string | null
  author: string
  readingTime: number
  publishedAt: string
}

export interface ApiComment {
  _id: string
  articleId: string
  author: string
  content: string
  createdAt: string
}

export interface ApiUser {
  _id: string
  email: string
  name: string
  role: string
}

export interface ApiAuthResponse {
  accessToken: string
  refreshToken: string
  user: ApiUser
}

export interface ApiArticlesResponse {
  articles: ApiArticleSummary[]
  total: number
  page: number
  limit: number
  totalPages: number
}

// ── Helpers ───────────────────────────────────────────────────────────────────

async function apiFetch<T>(
  endpoint: string,
  options: RequestInit = {}
): Promise<T> {
  const controller = new AbortController()
  const timeout = setTimeout(() => controller.abort(), TIMEOUT)

  try {
    const res = await fetch(`${API_URL}${endpoint}`, {
      ...options,
      signal: controller.signal,
      headers: {
        'Content-Type': 'application/json',
        ...options.headers,
      },
      credentials: 'include',
    })

    if (!res.ok) {
      const error = await res.json().catch(() => ({ message: res.statusText }))
      throw new Error(error.message || `HTTP ${res.status}`)
    }

    return res.json()
  } finally {
    clearTimeout(timeout)
  }
}

function getAuthHeader(): Record<string, string> {
  if (typeof window === 'undefined') return {}
  const token = localStorage.getItem('maiy_access_token')
  if (!token) return {}
  return { Authorization: `Bearer ${token}` }
}

// ── Articles ─────────────────────────────────────────────────────────────────

export async function fetchArticles(params?: {
  page?: number
  limit?: number
  category?: string
}): Promise<ApiArticlesResponse> {
  const qs = new URLSearchParams(
    Object.entries(params || {}).reduce((acc, [k, v]) => {
      if (v !== undefined && v !== null) acc[k] = String(v)
      return acc
    }, {} as Record<string, string>)
  ).toString()

  return apiFetch<ApiArticlesResponse>(
    `/api/articles${qs ? `?${qs}` : ''}`
  )
}

export async function fetchArticle(slug: string): Promise<ApiArticle | null> {
  try {
    return await apiFetch<ApiArticle>(`/api/articles/${slug}`)
  } catch {
    return null
  }
}

export async function fetchComments(articleSlug: string): Promise<ApiComment[]> {
  try {
    return await apiFetch<ApiComment[]>(`/api/articles/${articleSlug}/comments`)
  } catch {
    return []
  }
}

// ── Auth ──────────────────────────────────────────────────────────────────────

export async function login(email: string, password: string): Promise<ApiAuthResponse> {
  return apiFetch<ApiAuthResponse>('/api/auth/login', {
    method: 'POST',
    body: JSON.stringify({ email, password }),
  })
}

export async function register(
  email: string,
  password: string,
  name: string
): Promise<ApiAuthResponse> {
  return apiFetch<ApiAuthResponse>('/api/auth/register', {
    method: 'POST',
    body: JSON.stringify({ email, password, name }),
  })
}

export async function logout(): Promise<void> {
  try {
    await apiFetch('/api/auth/logout', { method: 'POST' })
  } finally {
    if (typeof window !== 'undefined') {
      localStorage.removeItem('maiy_access_token')
      localStorage.removeItem('maiy_refresh_token')
    }
  }
}

// ── User ──────────────────────────────────────────────────────────────────────

export async function fetchCurrentUser(): Promise<ApiUser | null> {
  try {
    return await apiFetch<ApiUser>('/api/users/me', {
      headers: getAuthHeader(),
    })
  } catch {
    return null
  }
}

export async function updateProfile(data: Partial<ApiUser>): Promise<ApiUser> {
  return apiFetch<ApiUser>('/api/users/me', {
    method: 'PUT',
    headers: getAuthHeader(),
    body: JSON.stringify(data),
  })
}

// ── Newsletter ────────────────────────────────────────────────────────────────

export async function subscribeNewsletter(
  email: string,
  name?: string
): Promise<{ success: boolean; message: string }> {
  return apiFetch<{ success: boolean; message: string }>('/api/newsletter/subscribe', {
    method: 'POST',
    body: JSON.stringify({ email, name }),
  })
}

export async function unsubscribeNewsletter(
  email: string
): Promise<{ success: boolean; message: string }> {
  return apiFetch<{ success: boolean; message: string }>('/api/newsletter/unsubscribe', {
    method: 'POST',
    body: JSON.stringify({ email }),
  })
}

// ── Comments ─────────────────────────────────────────────────────────────────

export async function postComment(
  articleSlug: string,
  content: string,
  author: string
): Promise<ApiComment> {
  return apiFetch<ApiComment>(`/api/articles/${articleSlug}/comments`, {
    method: 'POST',
    headers: getAuthHeader(),
    body: JSON.stringify({ content, author }),
  })
}

export async function deleteComment(commentId: string): Promise<void> {
  await apiFetch(`/api/comments/${commentId}`, {
    method: 'DELETE',
    headers: getAuthHeader(),
  })
}

// ── Rooms ─────────────────────────────────────────────────────────────────────

export async function createRoom(
  name: string,
  description?: string
): Promise<{ code: string; name: string }> {
  return apiFetch('/api/rooms/create', {
    method: 'POST',
    headers: getAuthHeader(),
    body: JSON.stringify({ name, description }),
  })
}

export async function fetchRoom(code: string): Promise<any> {
  return apiFetch(`/api/rooms/${code}`)
}

// ── JWT Token helpers (client-side) ───────────────────────────────────────────

export function setTokens(accessToken: string, refreshToken?: string): void {
  if (typeof window === 'undefined') return
  localStorage.setItem('maiy_access_token', accessToken)
  if (refreshToken) localStorage.setItem('maiy_refresh_token', refreshToken)
}

export function getAccessToken(): string | null {
  if (typeof window === 'undefined') return null
  return localStorage.getItem('maiy_access_token')
}

export function clearTokens(): void {
  if (typeof window === 'undefined') return
  localStorage.removeItem('maiy_access_token')
  localStorage.removeItem('maiy_refresh_token')
}

// ── Content layer — maps to Backend MongoDB API ───────────────────────────────
// All article data now comes from the Fastify backend via /api/articles
//
// NOTE: For SSR in Next.js App Router, fetch() uses absolute URLs by default.
// NEXT_PUBLIC_API_URL is set to the backend base URL (e.g. http://localhost:4000).

import { fetchArticles, fetchArticle as fetchArticleApi, type ApiArticleSummary, type ApiArticle } from './api'
import type { ArticleSummary } from '@/components/blog/article-card'

// ── Re-export Article type for convenience ────────────────────────────────────
export type { ArticleSummary }

// ── Internal helpers ──────────────────────────────────────────────────────────

/** Full article with content (returned by getArticleBySlug) */
export interface Article extends ArticleSummary {
  content: string
}

/** Map API article summary → frontend ArticleSummary (matches ArticleCard) */
function mapSummary(a: ApiArticleSummary): ArticleSummary {
  return {
    slug: a.slug,
    title: a.title,
    excerpt: a.excerpt,
    category: a.category,
    tags: a.tags ?? [],
    hero: a.hero ?? null,
    author: a.author,
    readingTime: a.readingTime ?? 5,
    publishedAt: a.publishedAt,
  }
}

/** Map API full article → frontend Article (with content) */
function mapArticle(a: ApiArticle): Article {
  return {
    ...mapSummary(a),
    content: a.content ?? '',
  }
}

// ── Public API (mirrors old MDX interface) ───────────────────────────────────

export async function getAllArticles(): Promise<ArticleSummary[]> {
  try {
    const res = await fetchArticles({ limit: 100 })
    return res.articles.map(mapSummary)
  } catch (err) {
    console.error('[content] getAllArticles failed:', err)
    return []
  }
}

export async function getRecentArticles(limit = 6): Promise<ArticleSummary[]> {
  try {
    const res = await fetchArticles({ limit })
    return res.articles.map(mapSummary)
  } catch (err) {
    console.error('[content] getRecentArticles failed:', err)
    return []
  }
}

export async function getFeaturedArticles(): Promise<ArticleSummary[]> {
  return getAllArticles()
}

export async function getArticleBySlug(slug: string): Promise<(ArticleSummary & { content: string }) | null> {
  try {
    const article = await fetchArticleApi(slug)
    if (!article) return null
    return mapArticle(article)
  } catch (err) {
    console.error(`[content] getArticleBySlug(${slug}) failed:`, err)
    return null
  }
}

export async function getArticlesByCategory(category: string): Promise<ArticleSummary[]> {
  try {
    const res = await fetchArticles({ category, limit: 100 })
    return res.articles.map(mapSummary)
  } catch (err) {
    console.error(`[content] getArticlesByCategory(${category}) failed:`, err)
    return []
  }
}

export async function getAllSlugs(): Promise<string[]> {
  try {
    const res = await fetchArticles({ limit: 1000 })
    return res.articles.map((a) => a.slug)
  } catch (err) {
    console.error('[content] getAllSlugs failed:', err)
    return []
  }
}

import { Metadata } from 'next'
import { SITE } from '@/config/site'
import Link from 'next/link'
import { getAllArticles } from '@/lib/content'
import { Tag, Hash } from 'lucide-react'

export const metadata: Metadata = {
  title: 'Tags',
  description: 'Tất cả tags trên MAIY Tech Hub — khám phá bài viết theo chủ đề và từ khóa.',
  alternates: { canonical: `${SITE.url}/tags` },
  openGraph: {
    type: 'website',
    title: 'Tags | MAIY Tech Hub',
    description: 'Tất cả tags trên MAIY Tech Hub.',
    url: `${SITE.url}/tags`,
    siteName: 'MAIY Tech Hub',
    locale: 'vi_VN',
  },
  twitter: { card: 'summary', title: 'Tags | MAIY Tech Hub', description: 'Tất cả tags trên MAIY Tech Hub.' },
}

const TAG_COLORS = [
  { bg: 'bg-blue-500/10 hover:bg-blue-500/20', border: 'border-blue-500/20', text: 'text-blue-400', icon: '#3b82f6' },
  { bg: 'bg-violet-500/10 hover:bg-violet-500/20', border: 'border-violet-500/20', text: 'text-violet-400', icon: '#8b5cf6' },
  { bg: 'bg-emerald-500/10 hover:bg-emerald-500/20', border: 'border-emerald-500/20', text: 'text-emerald-400', icon: '#10b981' },
  { bg: 'bg-amber-500/10 hover:bg-amber-500/20', border: 'border-amber-500/20', text: 'text-amber-400', icon: '#f59e0b' },
  { bg: 'bg-pink-500/10 hover:bg-pink-500/20', border: 'border-pink-500/20', text: 'text-pink-400', icon: '#ec4899' },
  { bg: 'bg-cyan-500/10 hover:bg-cyan-500/20', border: 'border-cyan-500/20', text: 'text-cyan-400', icon: '#06b6d4' },
  { bg: 'bg-red-500/10 hover:bg-red-500/20', border: 'border-red-500/20', text: 'text-red-400', icon: '#ef4444' },
  { bg: 'bg-orange-500/10 hover:bg-orange-500/20', border: 'border-orange-500/20', text: 'text-orange-400', icon: '#f97316' },
]

export default async function TagsPage() {
  const articles = await getAllArticles()

  const tagMap = new Map<string, number>()
  articles.forEach((a) => a.tags.forEach((tag) => tagMap.set(tag, (tagMap.get(tag) || 0) + 1)))
  const tags = Array.from(tagMap.entries()).sort((a, b) => b[1] - a[1])

  return (
    <div className="min-h-screen">
      {/* Clean background — no blur orbs, no heavy effects */}
      <div className="fixed inset-0 pointer-events-none -z-10 bg-gradient-to-b from-[#0a0a18] via-[#0c0c1a] to-[#0a0a18]" />

      {/* Subtle top gradient accent */}
      <div className="fixed top-0 left-1/2 -translate-x-1/2 w-[600px] h-[200px] pointer-events-none -z-5 bg-violet-600/[0.03] blur-[80px]" />

      {/* Header */}
      <section className="relative py-20 px-6 md:px-12">
        <div className="max-w-5xl mx-auto">
          <div className="flex items-center gap-3 mb-5">
            <div className="w-11 h-11 rounded-xl bg-gradient-to-br from-violet-500 to-indigo-500 flex items-center justify-center shadow-lg shadow-violet-500/25">
              <Hash className="h-5 w-5 text-white" />
            </div>
            <span className="text-xs font-bold uppercase tracking-[0.2em] text-white/25">Khám phá</span>
          </div>
          <h1 className="text-5xl md:text-6xl font-black tracking-tight mb-4">
            <span className="bg-gradient-to-r from-violet-300 via-purple-300 to-indigo-300 bg-clip-text text-transparent">Tags</span>
          </h1>
          <p className="text-white/35 text-base">{tags.length} tags · {articles.length} bài viết</p>
        </div>
      </section>

      {/* Tag cloud — simple, fast */}
      <section className="px-6 md:px-12 pb-10">
        <div className="max-w-5xl mx-auto">
          <div className="flex items-center gap-3 mb-6">
            <div className="w-1 h-6 rounded-full bg-gradient-to-b from-violet-500 to-indigo-500" />
            <h2 className="text-sm font-bold uppercase tracking-[0.15em] text-white/35">Tất cả tags</h2>
          </div>

          <div className="flex flex-wrap gap-2.5">
            {tags.map(([tag, count], i) => {
              const c = TAG_COLORS[i % TAG_COLORS.length]
              return (
                <Link
                  key={tag}
                  href={`/search?q=${encodeURIComponent(tag)}`}
                  className={`inline-flex items-center gap-2 px-4 py-2 rounded-xl border transition-colors duration-200 ${c.bg} ${c.border}`}
                >
                  <Tag className="h-3.5 w-3.5 flex-shrink-0" style={{ color: c.icon }} />
                  <span className="text-sm font-medium" style={{ color: c.icon }}>{tag}</span>
                  <span
                    className="px-1.5 py-0.5 rounded-full text-[10px] font-bold"
                    style={{ backgroundColor: c.icon + '18', color: c.icon }}
                  >
                    {count}
                  </span>
                </Link>
              )
            })}
          </div>
        </div>
      </section>

      {/* Popular tags — card grid */}
      {tags.length > 0 && (
        <section className="px-6 md:px-12 pb-20">
          <div className="max-w-5xl mx-auto">
            <div className="flex items-center gap-3 mb-6">
              <div className="w-1 h-6 rounded-full bg-gradient-to-b from-pink-500 to-rose-500" />
              <h2 className="text-sm font-bold uppercase tracking-[0.15em] text-white/35">Phổ biến nhất</h2>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
              {tags.slice(0, 9).map(([tag, count], i) => {
                const c = TAG_COLORS[i % TAG_COLORS.length]
                return (
                  <Link
                    key={tag}
                    href={`/search?q=${encodeURIComponent(tag)}`}
                    className={`group flex items-center justify-between p-4 rounded-xl border transition-colors duration-200 ${c.bg} ${c.border}`}
                  >
                    <div className="flex items-center gap-3">
                      <div
                        className="w-10 h-10 rounded-lg flex items-center justify-center flex-shrink-0"
                        style={{ backgroundColor: c.icon + '15', border: `1px solid ${c.icon}25` }}
                      >
                        <Tag className="h-4 w-4" style={{ color: c.icon }} />
                      </div>
                      <div>
                        <p className="font-semibold text-sm" style={{ color: c.icon }}>{tag}</p>
                        <p className="text-xs text-white/30">{count} bài</p>
                      </div>
                    </div>
                    <div
                      className="w-7 h-7 rounded-full flex items-center justify-center text-xs font-bold flex-shrink-0"
                      style={{ backgroundColor: c.icon + '12', color: c.icon, border: `1px solid ${c.icon}20` }}
                    >
                      {i + 1}
                    </div>
                  </Link>
                )
              })}
            </div>
          </div>
        </section>
      )}

      {tags.length === 0 && (
        <div className="px-6 pb-20 text-center">
          <div className="inline-flex items-center justify-center w-20 h-20 rounded-full bg-white/[0.02] border border-white/[0.06] mb-6">
            <Tag className="h-10 w-10 text-white/[0.08]" />
          </div>
          <p className="text-white/20 text-lg font-medium mb-2">Chưa có tags nào</p>
          <p className="text-white/10 text-sm">Bài viết đầu tiên sẽ tạo tags tự động.</p>
        </div>
      )}
    </div>
  )
}

import { Metadata } from 'next'
import { getAllArticles } from '@/lib/content'
import { SearchContent } from '@/components/blog/search-content'
import { SITE } from '@/config/site'

export const metadata: Metadata = {
  title: 'Tìm kiếm',
  description: 'Tìm kiếm bài viết trên MAIY Tech Hub theo chủ đề, tags, hoặc từ khóa.',
  alternates: {
    canonical: `${SITE.url}/search`,
  },
  openGraph: {
    type: 'website',
    title: 'Tìm kiếm | MAIY Tech Hub',
    description: 'Tìm kiếm bài viết trên MAIY Tech Hub theo chủ đề, tags, hoặc từ khóa.',
    url: `${SITE.url}/search`,
    siteName: 'MAIY Tech Hub',
    locale: 'vi_VN',
  },
  twitter: {
    card: 'summary',
    title: 'Tìm kiếm | MAIY Tech Hub',
    description: 'Tìm kiếm bài viết trên MAIY Tech Hub.',
  },
}

export default async function SearchPage() {
  const articles = await getAllArticles()
  return <SearchContent articles={articles} />
}

'use client'

import { useState, useEffect, useMemo } from 'react'
import { Search, X, FileText } from 'lucide-react'
import Link from 'next/link'
import Fuse from 'fuse.js'
import type { ArticleSummary } from './article-card'

interface SearchContentProps {
  articles: ArticleSummary[]
}

const CATEGORIES = [
  { slug: 'ctdl', label: 'CTDL' },
  { slug: 'ai', label: 'AI' },
  { slug: 'web-dev', label: 'Web Dev' },
  { slug: 'devops', label: 'DevOps' },
  { slug: 'cs-fundamentals', label: 'CS' },
]

export function SearchContent({ articles }: SearchContentProps) {
  const [query, setQuery] = useState('')
  const [results, setResults] = useState<ArticleSummary[]>([])
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null)

  const fuse = useMemo(
    () =>
      new Fuse(articles, {
        keys: ['title', 'excerpt', 'tags', 'category'],
        threshold: 0.4,
        includeScore: true,
      }),
    [articles]
  )

  useEffect(() => {
    if (!query.trim()) {
      setResults(
        selectedCategory
          ? articles.filter((a) => a.category === selectedCategory)
          : []
      )
      return
    }
    const r = fuse.search(query)
    let filtered = r.map((x) => x.item)
    if (selectedCategory) {
      filtered = filtered.filter((a) => a.category === selectedCategory)
    }
    setResults(filtered)
  }, [query, selectedCategory, fuse, articles])

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault()
        document.getElementById('search-input')?.focus()
      }
    }
    document.addEventListener('keydown', handler)
    return () => document.removeEventListener('keydown', handler)
  }, [])

  return (
    <div className="container py-12 max-w-4xl mx-auto">
      <h1 className="text-3xl font-bold mb-8">Tìm kiếm</h1>

      {/* Search input */}
      <div className="relative mb-6">
        <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-5 w-5 text-muted-foreground" />
        <input
          id="search-input"
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="Tìm bài viết, tags, chủ đề..."
          className="w-full pl-12 pr-12 py-4 rounded-xl border border-border bg-background text-base focus:outline-none focus:ring-2 focus:ring-ring"
          autoFocus
        />
        {query && (
          <button
            onClick={() => setQuery('')}
            className="absolute right-4 top-1/2 -translate-y-1/2 p-1 rounded hover:bg-accent transition-colors"
            aria-label="Xóa"
          >
            <X className="h-4 w-4 text-muted-foreground" />
          </button>
        )}
      </div>

      {/* Category filter */}
      <div className="flex flex-wrap gap-2 mb-8">
        <button
          onClick={() => setSelectedCategory(null)}
          className={`px-3 py-1.5 rounded-full text-sm font-medium transition-all ${
            !selectedCategory
              ? 'bg-primary text-primary-foreground'
              : 'border border-border hover:border-primary/50 hover:bg-primary/5'
          }`}
        >
          Tất cả
        </button>
        {CATEGORIES.map((cat) => (
          <button
            key={cat.slug}
            onClick={() =>
              setSelectedCategory(selectedCategory === cat.slug ? null : cat.slug)
            }
            className={`px-3 py-1.5 rounded-full text-sm font-medium transition-all ${
              selectedCategory === cat.slug
                ? 'bg-primary text-primary-foreground'
                : 'border border-border hover:border-primary/50 hover:bg-primary/5'
            }`}
          >
            {cat.label}
          </button>
        ))}
      </div>

      {/* Results */}
      {results.length > 0 ? (
        <>
          <p className="text-sm text-muted-foreground mb-6">
            {query
              ? `Tìm thấy ${results.length} kết quả cho "${query}"`
              : `${results.length} bài viết`}
          </p>
          <div className="space-y-3">
            {results.map((article) => (
              <Link
                key={article.slug}
                href={`/articles/${article.slug}`}
                className="flex items-start gap-4 p-4 rounded-xl border border-border hover:border-primary/50 hover:bg-accent/30 transition-all group"
              >
                <FileText className="h-5 w-5 text-muted-foreground mt-0.5 flex-shrink-0 group-hover:text-primary transition-colors" />
                <div className="flex-1 min-w-0">
                  <p className="font-medium group-hover:text-primary transition-colors line-clamp-1">
                    {article.title}
                  </p>
                  <p className="text-sm text-muted-foreground line-clamp-2 mt-1">
                    {article.excerpt}
                  </p>
                  <div className="flex items-center gap-3 mt-2">
                    <span className="text-xs text-muted-foreground capitalize">{article.category}</span>
                    <span className="text-xs text-muted-foreground">
                      {article.readingTime} phút đọc
                    </span>
                  </div>
                </div>
              </Link>
            ))}
          </div>
        </>
      ) : query ? (
        <div className="text-center py-16">
          <Search className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
          <p className="text-lg text-muted-foreground">
            Không tìm thấy kết quả cho &ldquo;{query}&rdquo;
          </p>
          <p className="text-sm text-muted-foreground mt-2">
            Thử từ khóa khác hoặc bỏ lọc danh mục
          </p>
        </div>
      ) : (
        <div className="text-center py-16">
          <Search className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
