'use client'

import { useState, useEffect, useCallback } from 'react'
import Link from 'next/link'
import { Plus, Eye, FileText, Trash2, Globe, GlobeLock, Loader2, RefreshCw } from 'lucide-react'
import { fetchAdminArticles, deleteArticle, togglePublish, getAccessToken } from '@/lib/api'
import { useRouter } from 'next/navigation'

interface AdminArticle {
  id: string
  slug: string
  title: string
  excerpt: string
  category: string
  tags: string[]
  coverImage?: string | null
  readingTime: number
  publishedAt: string | null
  published: boolean
  author: { id: string; name: string; avatar?: string | null }
}

export default function AdminArticlesPage() {
  const router = useRouter()
  const [articles, setArticles] = useState<AdminArticle[]>([])
  const [loading, setLoading] = useState(true)
  const [deleting, setDeleting] = useState<string | null>(null)
  const [toggling, setToggling] = useState<string | null>(null)
  const [filter, setFilter] = useState<'all' | 'published' | 'draft'>('all')

  const load = useCallback(async () => {
    const token = getAccessToken()
    if (!token) {
      router.push('/admin/login')
      return
    }
    try {
      const data = await fetchAdminArticles()
      setArticles(data as AdminArticle[])
    } catch (err) {
      console.error('[admin] fetchAdminArticles failed:', err)
    } finally {
      setLoading(false)
    }
  }, [router])

  useEffect(() => { load() }, [load])

  const handleDelete = async (id: string, title: string) => {
    if (!confirm(`Xóa bài viết "${title}"? Hành động này không thể hoàn tác.`)) return
    setDeleting(id)
    try {
      await deleteArticle(id)
      setArticles((prev) => prev.filter((a) => a.id !== id))
    } catch (err) {
      console.error('[admin] deleteArticle failed:', err)
      alert('Xóa thất bại. Vui lòng thử lại.')
    } finally {
      setDeleting(null)
    }
  }

  const handleTogglePublish = async (id: string, current: boolean) => {
    setToggling(id)
    try {
      const updated = await togglePublish(id, !current)
      setArticles((prev) =>
        prev.map((a) =>
          a.id === id ? { ...a, published: updated.published } : a
        )
      )
    } catch (err) {
      console.error('[admin] togglePublish failed:', err)
      alert('Cập nhật thất bại. Vui lòng thử lại.')
    } finally {
      setToggling(null)
    }
  }

  const filtered = articles.filter((a) => {
    if (filter === 'published') return a.published
    if (filter === 'draft') return !a.published
    return true
  })

  const CATEGORY_LABELS: Record<string, string> = {
    AI: 'AI',
    CTDL: 'CTDL',
    WEB_DEV: 'Web Dev',
    DEVOPS: 'DevOps',
    MOBILE: 'Mobile',
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">Quản lý bài viết</h1>
          <p className="text-sm text-muted-foreground mt-1">
            {articles.length} bài viết · {articles.filter((a) => a.published).length} đã đăng ·{' '}
            {articles.filter((a) => !a.published).length} nháp
          </p>
        </div>
        <div className="flex items-center gap-2">
          <button
            onClick={load}
            className="p-2 rounded-lg border border-border hover:bg-accent transition-colors"
            title="Làm mới"
          >
            <RefreshCw className="h-4 w-4" />
          </button>
          <Link
            href="/admin/articles/new"
            className="inline-flex items-center gap-2 px-4 py-2 rounded-lg bg-primary text-primary-foreground font-medium text-sm hover:bg-primary/90 transition-colors"
          >
            <Plus className="h-4 w-4" />
            Bài viết mới
          </Link>
        </div>
      </div>

      {/* Status filter */}
      <div className="flex flex-wrap gap-2">
        {[
          { key: 'all', label: `Tất cả (${articles.length})` },
          { key: 'published', label: `Đã đăng (${articles.filter((a) => a.published).length})` },
          { key: 'draft', label: `Nháp (${articles.filter((a) => !a.published).length})` },
        ].map(({ key, label }) => (
          <button
            key={key}
            onClick={() => setFilter(key as typeof filter)}
            className={`px-3 py-1.5 rounded-full text-sm font-medium transition-all ${
              filter === key
                ? 'bg-primary text-primary-foreground'
                : 'border border-border hover:border-primary/50 hover:bg-primary/5'
            }`}
          >
            {label}
          </button>
        ))}
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-20">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : filtered.length === 0 ? (
        <div className="text-center py-20 text-muted-foreground">
          <FileText className="h-12 w-12 mx-auto mb-4 opacity-20" />
          <p>Chưa có bài viết nào.</p>
          <Link href="/admin/articles/new" className="text-primary hover:underline mt-2 inline-block">
            Tạo bài viết đầu tiên →
          </Link>
        </div>
      ) : (
        <div className="rounded-xl border border-border overflow-hidden">
          <table className="w-full text-sm">
            <thead className="border-b border-border bg-muted/30">
              <tr>
                <th className="text-left px-4 py-3 font-medium text-muted-foreground">Tiêu đề</th>
                <th className="text-left px-4 py-3 font-medium text-muted-foreground hidden md:table-cell">Chủ đề</th>
                <th className="text-left px-4 py-3 font-medium text-muted-foreground hidden lg:table-cell">Tags</th>
                <th className="text-left px-4 py-3 font-medium text-muted-foreground">Trạng thái</th>
                <th className="text-right px-4 py-3 font-medium text-muted-foreground">Thao tác</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-border">
              {filtered.map((article) => (
                <tr key={article.id} className="hover:bg-accent/20 transition-colors">
                  <td className="px-4 py-3">
                    <div className="font-medium line-clamp-1">{article.title}</div>
                    <div className="flex items-center gap-3 mt-1">
                      <span className="text-xs text-muted-foreground">{article.readingTime} phút</span>
                      <span className="text-xs text-muted-foreground">
                        {article.publishedAt
                          ? new Date(article.publishedAt).toLocaleDateString('vi-VN')
                          : '—'}
                      </span>
                    </div>
                  </td>
                  <td className="px-4 py-3 hidden md:table-cell">
                    <span className="px-2 py-0.5 text-xs rounded-full bg-primary/10 text-primary">
                      {CATEGORY_LABELS[article.category] ?? article.category}
                    </span>
                  </td>
                  <td className="px-4 py-3 hidden lg:table-cell">
                    <div className="flex flex-wrap gap-1 max-w-[200px]">
                      {(article.tags ?? []).slice(0, 3).map((tag) => (
                        <span key={tag} className="px-1.5 py-0.5 text-xs rounded bg-muted text-muted-foreground">
                          #{tag}
                        </span>
                      ))}
                      {(article.tags ?? []).length > 3 && (
                        <span className="text-xs text-muted-foreground">+{article.tags.length - 3}</span>
                      )}
                    </div>
                  </td>
                  <td className="px-4 py-3">
                    {article.published ? (
                      <span className="inline-flex items-center gap-1 text-xs font-medium text-emerald-500">
                        <Globe className="h-3 w-3" />
                        Đã đăng
                      </span>
                    ) : (
                      <span className="inline-flex items-center gap-1 text-xs font-medium text-amber-500">
                        <GlobeLock className="h-3 w-3" />
                        Nháp
                      </span>
                    )}
                  </td>
                  <td className="px-4 py-3">
                    <div className="flex items-center justify-end gap-1">
                      {/* Toggle publish */}
                      <button
                        onClick={() => handleTogglePublish(article.id, article.published)}
                        disabled={toggling === article.id}
                        className={`p-1.5 rounded hover:bg-accent transition-colors ${
                          article.published
                            ? 'text-amber-500 hover:text-amber-400'
                            : 'text-emerald-500 hover:text-emerald-400'
                        }`}
                        title={article.published ? 'Chuyển sang nháp' : 'Xuất bản'}
                      >
                        {toggling === article.id ? (
                          <Loader2 className="h-3.5 w-3.5 animate-spin" />
                        ) : article.published ? (
                          <GlobeLock className="h-3.5 w-3.5" />
                        ) : (
                          <Globe className="h-3.5 w-3.5" />
                        )}
                      </button>

                      {/* View */}
                      <a
                        href={`/articles/${article.slug}`}
                        target="_blank"
                        className="p-1.5 rounded hover:bg-accent text-muted-foreground hover:text-foreground transition-colors"
                        title="Xem bài viết"
                      >
                        <Eye className="h-3.5 w-3.5" />
                      </a>

                      {/* Edit */}
                      <Link
                        href={`/admin/articles/${article.id}`}
                        className="p-1.5 rounded hover:bg-accent text-muted-foreground hover:text-foreground transition-colors"
                        title="Sửa bài viết"
                      >
                        <FileText className="h-3.5 w-3.5" />
                      </Link>

                      {/* Delete */}
                      <button
                        onClick={() => handleDelete(article.id, article.title)}
                        disabled={deleting === article.id}
                        className="p-1.5 rounded hover:bg-red-500/10 text-muted-foreground hover:text-red-400 transition-colors"
                        title="Xóa bài viết"
                      >
                        {deleting === article.id ? (
                          <Loader2 className="h-3.5 w-3.5 animate-spin" />
                        ) : (
                          <Trash2 className="h-3.5 w-3.5" />
                        )}
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  )
}

'use client'

import { useState, useEffect, useRef } from 'react'
import { useRouter } from 'next/navigation'
import Link from 'next/link'
import { Save, Eye, Loader2, ArrowLeft, Upload, Globe, GlobeLock, X } from 'lucide-react'
import { CATEGORIES } from '@/config/site'
import { updateArticle, fetchArticle, uploadImage, getAccessToken } from '@/lib/api'

const BACKEND_CATEGORIES: Record<string, string> = {
  ctdl: 'CTDL',
  ai: 'AI',
  'web-dev': 'WEB_DEV',
  devops: 'DEVOPS',
  cs_fundamentals: 'CS',
}

const FRONTEND_CATEGORY_MAP: Record<string, string> = {
  CTDL: 'ctdl',
  AI: 'ai',
  WEB_DEV: 'web-dev',
  DEVOPS: 'devops',
  MOBILE: 'mobile',
}

interface Article {
  id: string
  slug: string
  title: string
  excerpt: string
  content: string
  category: string
  tags: string[]
  coverImage?: string | null
  readingTime: number
  published: boolean
  publishedAt: string | null
}

export default function EditArticlePage({ params }: { params: Promise<{ id: string }> }) {
  const router = useRouter()
  const [resolvedParams, setResolvedParams] = useState<{ id: string } | null>(null)
  const [article, setArticle] = useState<Article | null>(null)
  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState(false)
  const [uploading, setUploading] = useState(false)
  const [form, setForm] = useState({
    title: '',
    excerpt: '',
    category: 'ctdl',
    tags: '',
    hero: '',
    content: '',
    published: false,
  })
  const fileInputRef = useRef<HTMLInputElement>(null)

  // Resolve params (Next.js 15 async params)
  useEffect(() => {
    params.then(setResolvedParams)
  }, [params])

  // Load article
  useEffect(() => {
    if (!resolvedParams) return
    const token = getAccessToken()
    if (!token) { router.push('/admin/login'); return }

    const load = async () => {
      try {
        const data = await fetchArticle(resolvedParams.id) as Article
        setArticle(data)
        setForm({
          title: data.title ?? '',
          excerpt: data.excerpt ?? '',
          category: FRONTEND_CATEGORY_MAP[data.category] ?? 'ctdl',
          tags: (data.tags ?? []).join(', '),
          hero: data.coverImage ?? '',
          content: data.content ?? '',
          published: data.published ?? false,
        })
      } catch (err) {
        console.error('[admin] fetchArticle failed:', err)
        alert('Không thể tải bài viết.')
        router.push('/admin/articles')
      } finally {
        setLoading(false)
      }
    }
    load()
  }, [resolvedParams, router])

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file) return
    setUploading(true)
    try {
      const result = await uploadImage(file)
      setForm((f) => ({ ...f, hero: result.url }))
    } catch (err) {
      console.error('[admin] uploadImage failed:', err)
      alert('Upload ảnh thất bại. Vui lòng thử lại.')
    } finally {
      setUploading(false)
      if (fileInputRef.current) fileInputRef.current.value = ''
    }
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!article || !resolvedParams) return
    setSaving(true)
    try {
      const tags = form.tags
        .split(',')
        .map((t) => t.trim())
        .filter(Boolean)
      const readingTime = Math.max(1, Math.ceil(form.content.split(/\s+/).length / 200))

      await updateArticle(article.id, {
        title: form.title,
        excerpt: form.excerpt,
        category: BACKEND_CATEGORIES[form.category] ?? 'CTDL',
        tags,
        coverImage: form.hero || undefined,
        content: form.content,
        readingTime,
        published: form.published,
      })
      alert('Bài viết đã được cập nhật!')
      router.push('/admin/articles')
    } catch (err: any) {
      console.error('[admin] updateArticle failed:', err)
      alert(`Cập nhật thất bại: ${err.message}`)
    } finally {
      setSaving(false)
    }
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center py-20">
        <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
      </div>
    )
  }

  return (
    <div className="max-w-4xl">
      <div className="flex items-center justify-between mb-6">
        <div>
          <Link
            href="/admin/articles"
            className="inline-flex items-center gap-1 text-sm text-muted-foreground hover:text-primary transition-colors mb-2"
          >
            <ArrowLeft className="h-3.5 w-3.5" />
            Quay lại danh sách
          </Link>
          <h1 className="text-2xl font-bold">Sửa bài viết</h1>
        </div>
        <div className="flex items-center gap-2">
          {article && (
            <a
              href={`/articles/${article.slug}`}
              target="_blank"
              className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-lg border border-border text-sm text-muted-foreground hover:text-foreground hover:bg-accent transition-colors"
            >
              <Eye className="h-3.5 w-3.5" />
              Xem trước
            </a>
          )}
        </div>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Basic info */}
        <div className="rounded-xl border border-border bg-background p-6 space-y-4">
          <div className="flex items-center justify-between">
            <h2 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">
              Thông tin cơ bản
            </h2>
            <label className="flex items-center gap-2 cursor-pointer select-none">
              <input
                type="checkbox"
                checked={form.published}
                onChange={(e) => setForm({ ...form, published: e.target.checked })}
                className="sr-only peer"
              />
              <div className="relative w-10 h-5 bg-muted rounded-full peer peer-checked:bg-emerald-500 transition-colors">
                <div className="absolute top-0.5 left-0.5 w-4 h-4 bg-white rounded-full shadow transition-transform peer-checked:translate-x-5" />
              </div>
              <span className="text-xs font-medium">
                {form.published ? (
                  <span className="flex items-center gap-1 text-emerald-500"><Globe className="h-3 w-3" /> Đã xuất bản</span>
                ) : (
                  <span className="flex items-center gap-1 text-amber-500"><GlobeLock className="h-3 w-3" /> Nháp</span>
                )}
              </span>
            </label>
          </div>

          <div>
            <label className="block text-sm font-medium mb-1.5">Tiêu đề *</label>
            <input
              type="text"
              value={form.title}
              onChange={(e) => setForm({ ...form, title: e.target.value })}
              required
              className="w-full px-4 py-2.5 rounded-lg border border-border bg-background text-sm focus:outline-none focus:ring-2 focus:ring-ring"
            />
          </div>

          <div>
            <label className="block text-sm font-medium mb-1.5">Mô tả ngắn *</label>
            <textarea
              value={form.excerpt}
              onChange={(e) => setForm({ ...form, excerpt: e.target.value })}
              required
              rows={2}
              className="w-full px-4 py-2.5 rounded-lg border border-border bg-background text-sm focus:outline-none focus:ring-2 focus:ring-ring resize-none"
            />
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1.5">Chủ đề</label>
              <select
                value={form.category}
                onChange={(e) => setForm({ ...form, category: e.target.value })}
                className="w-full px-4 py-2.5 rounded-lg border border-border bg-background text-sm focus:outline-none focus:ring-2 focus:ring-ring"
              >
                {CATEGORIES.map((cat) => (
                  <option key={cat.slug} value={cat.slug}>{cat.label}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium mb-1.5">Tags (phân cách bằng dấu phẩy)</label>
              <input
                type="text"
                value={form.tags}
                onChange={(e) => setForm({ ...form, tags: e.target.value })}
                placeholder="VD: binary-search, algorithm"
                className="w-full px-4 py-2.5 rounded-lg border border-border bg-background text-sm focus:outline-none focus:ring-2 focus:ring-ring"
              />
            </div>
          </div>

          {/* Cover image */}
          <div>
            <label className="block text-sm font-medium mb-1.5">Ảnh bìa</label>
            <div className="flex items-start gap-3">
              <div className="flex-1">
                <input
                  type="url"
                  value={form.hero}
                  onChange={(e) => setForm({ ...form, hero: e.target.value })}
                  placeholder="URL ảnh hoặc upload bên dưới"
                  className="w-full px-4 py-2.5 rounded-lg border border-border bg-background text-sm focus:outline-none focus:ring-2 focus:ring-ring"
                />
              </div>
              <input
                ref={fileInputRef}
                type="file"
                accept="image/*"
                onChange={handleImageUpload}
                className="hidden"
              />
              <button
                type="button"
                onClick={() => fileInputRef.current?.click()}
                disabled={uploading}
                className="inline-flex items-center gap-1.5 px-3 py-2.5 rounded-lg border border-border text-sm hover:bg-accent transition-colors disabled:opacity-50"
              >
                {uploading ? (
                  <><Loader2 className="h-4 w-4 animate-spin" /> Đang upload...</>
                ) : (
                  <><Upload className="h-4 w-4" /> Upload ảnh</>
                )}
              </button>
              {form.hero && (
                <button
                  type="button"
                  onClick={() => setForm({ ...form, hero: '' })}
                  className="p-2.5 rounded-lg border border-border text-muted-foreground hover:text-red-400 hover:border-red-400/30 transition-colors"
                >
                  <X className="h-4 w-4" />
                </button>
              )}
            </div>
            {form.hero && (
              <div className="mt-2 rounded-lg overflow-hidden border border-border">
                {/* eslint-disable-next-line @next/next/no-img-element */}
                <img src={form.hero} alt="Cover preview" className="h-32 w-full object-cover" />
              </div>
            )}
          </div>
        </div>

        {/* Content */}
        <div className="rounded-xl border border-border bg-background p-6 space-y-4">
          <h2 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">
            Nội dung (Markdown/MDX)
          </h2>

          <textarea
            value={form.content}
            onChange={(e) => setForm({ ...form, content: e.target.value })}
            rows={20}
            className="w-full px-4 py-3 rounded-lg border border-border bg-muted/30 text-sm font-mono focus:outline-none focus:ring-2 focus:ring-ring resize-y min-h-[400px]"
          />

          <div className="flex items-center justify-between">
            <p className="text-xs text-muted-foreground">
              {form.content.length} ký tự • ~{Math.ceil(form.content.split(/\s+/).length / 200)} phút đọc
            </p>
            <button
              type="submit"
              disabled={saving || !form.title.trim() || !form.excerpt.trim()}
              className="inline-flex items-center gap-2 px-5 py-2.5 rounded-lg bg-primary text-primary-foreground font-medium text-sm hover:bg-primary/90 transition-colors disabled:opacity-50"
            >
              {saving ? (
                <><Loader2 className="h-4 w-4 animate-spin" /> Đang lưu...</>
              ) : (
                <><Save className="h-4 w-4" /> Lưu thay đổi</>
              )}
            </button>
          </div>
        </div>
      </form>
    </div>
  )
}

'use client'

