        title: form.title,
        excerpt: form.excerpt,
        category: BACKEND_CATEGORIES[form.category] ?? 'CTDL',
        tags,
        coverImage: form.hero || undefined,
        content: form.content,
        readingTime,
        published: form.published,
      })

      alert(`Bài viết "${form.title}" đã được tạo!`)
      router.push('/admin/articles')
    } catch (err: any) {
      console.error('[admin] createArticle failed:', err)
      alert(`Tạo bài viết thất bại: ${err.message}`)
