        <div>
          <Link
            href="/admin/articles"
            className="inline-flex items-center gap-1 text-sm text-muted-foreground hover:text-primary transition-colors mb-2"
          >
            <ArrowLeft className="h-3.5 w-3.5" />
            Quay lại danh sách
          </Link>
          <h1 className="text-2xl font-bold">Bài viết mới</h1>
        </div>
        <a
          href="/articles"
          target="_blank"
          className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-lg border border-border text-sm text-muted-foreground hover:text-foreground hover:bg-accent transition-colors"
        >
          <Eye className="h-3.5 w-3.5" />
          Xem trước
        </a>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Basic info */}
        <div className="rounded-xl border border-border bg-background p-6 space-y-4">
          <h2 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">
            Thông tin cơ bản
          </h2>

          <div>
            <label className="block text-sm font-medium mb-1.5">Tiêu đề *</label>
            <input
              type="text"
              value={form.title}
              onChange={(e) => setForm({ ...form, title: e.target.value })}
              required
              placeholder="VD: Binary Search: Từ Cơ Bản đến Nâng Cao"
              className="w-full px-4 py-2.5 rounded-lg border border-border bg-background text-sm focus:outline-none focus:ring-2 focus:ring-ring"
            />
          </div>

          <div>
            <label className="block text-sm font-medium mb-1.5">Mô tả ngắn *</label>
            <textarea
              value={form.excerpt}
              onChange={(e) => setForm({ ...form, excerpt: e.target.value })}
              required
              rows={2}
              placeholder="Mô tả ngắn gọn 1-2 câu (hiển thị trên card)"
              className="w-full px-4 py-2.5 rounded-lg border border-border bg-background text-sm focus:outline-none focus:ring-2 focus:ring-ring resize-none"
            />
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1.5">Chủ đề</label>
              <select
                value={form.category}
                onChange={(e) => setForm({ ...form, category: e.target.value })}
                className="w-full px-4 py-2.5 rounded-lg border border-border bg-background text-sm focus:outline-none focus:ring-2 focus:ring-ring"
              >
                {CATEGORIES.map((cat) => (
                  <option key={cat.slug} value={cat.slug}>
                    {cat.label}
                  </option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium mb-1.5">Tags (phân cách bằng dấu phẩy)</label>
              <input
                type="text"
                value={form.tags}
                onChange={(e) => setForm({ ...form, tags: e.target.value })}
                placeholder="VD: binary-search, algorithm, interview"
                className="w-full px-4 py-2.5 rounded-lg border border-border bg-background text-sm focus:outline-none focus:ring-2 focus:ring-ring"
              />
            </div>
          </div>

          {/* Cover image — with upload */}
          <div>
            <label className="block text-sm font-medium mb-1.5">Ảnh bìa</label>
            <div className="flex items-start gap-3">
              <div className="flex-1">
                <input
                  type="url"
                  value={form.hero}
                  onChange={(e) => setForm({ ...form, hero: e.target.value })}
                  placeholder="URL ảnh hoặc upload bên dưới"
                  className="w-full px-4 py-2.5 rounded-lg border border-border bg-background text-sm focus:outline-none focus:ring-2 focus:ring-ring"
                />
              </div>
              <input
                ref={fileInputRef}
                type="file"
                accept="image/*"
                onChange={handleImageUpload}
                className="hidden"
              />
              <button
                type="button"
                onClick={() => fileInputRef.current?.click()}
                disabled={uploading}
                className="inline-flex items-center gap-1.5 px-3 py-2.5 rounded-lg border border-border text-sm hover:bg-accent transition-colors disabled:opacity-50"
              >
                {uploading ? (
                  <><Loader2 className="h-4 w-4 animate-spin" /> Đang upload...</>
                ) : (
                  <><Upload className="h-4 w-4" /> Upload ảnh</>
                )}
              </button>
              {form.hero && (
                <button
                  type="button"
                  onClick={() => setForm({ ...form, hero: '' })}
                  className="p-2.5 rounded-lg border border-border text-muted-foreground hover:text-red-400 hover:border-red-400/30 transition-colors"
                >
                  <X className="h-4 w-4" />
                </button>
              )}
            </div>
            {form.hero && (
              <div className="mt-2 rounded-lg overflow-hidden border border-border">
                {/* eslint-disable-next-line @next/next/no-img-element */}
                <img src={form.hero} alt="Cover preview" className="h-32 w-full object-cover" />
              </div>
            )}
          </div>

          {/* Publish toggle */}
          <div className="flex items-center gap-3 pt-2">
            <label className="flex items-center gap-2 cursor-pointer select-none">
              <input
                type="checkbox"
                checked={form.published}
                onChange={(e) => setForm({ ...form, published: e.target.checked })}
                className="sr-only peer"
              />
              <div className="relative w-10 h-5 bg-muted rounded-full peer peer-checked:bg-emerald-500 transition-colors">
                <div className="absolute top-0.5 left-0.5 w-4 h-4 bg-white rounded-full shadow transition-transform peer-checked:translate-x-5" />
              </div>
              <span className="text-xs font-medium text-muted-foreground">
                {form.published ? 'Đăng ngay sau khi lưu' : 'Lưu như bản nháp'}
              </span>
            </label>
          </div>
        </div>

        {/* Content */}
        <div className="rounded-xl border border-border bg-background p-6 space-y-4">
          <h2 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">
            Nội dung (Markdown/MDX)
          </h2>

          <p className="text-xs text-muted-foreground">
            Viết bài bằng Markdown. Code blocks dùng ```javascript ...```.
          </p>

          <textarea
            value={form.content}
            onChange={(e) => setForm({ ...form, content: e.target.value })}
            rows={20}
            placeholder={`# Tiêu đề bài viết

## Mục 1

Nội dung bài viết ở đây...

\`\`\`javascript
// Code example
const binarySearch = (arr, target) => {
  let left = 0, right = arr.length - 1
  while (left <= right) {
    const mid = Math.floor((left + right) / 2)
    if (arr[mid] === target) return mid
    if (arr[mid] < target) left = mid + 1
    else right = mid - 1
  }
  return -1
}
\`\`\`

## Mục 2

Tiếp tục viết nội dung...`}
            className="w-full px-4 py-3 rounded-lg border border-border bg-muted/30 text-sm font-mono focus:outline-none focus:ring-2 focus:ring-ring resize-y min-h-[400px]"
          />

          <div className="flex items-center justify-between">
            <p className="text-xs text-muted-foreground">
              {form.content.length} ký tự • ~{Math.ceil(form.content.split(/\s+/).length / 200)} phút đọc
            </p>
            <button
              type="submit"
              disabled={loading || !form.title.trim() || !form.excerpt.trim()}
              className="inline-flex items-center gap-2 px-5 py-2.5 rounded-lg bg-primary text-primary-foreground font-medium text-sm hover:bg-primary/90 transition-colors disabled:opacity-50"
            >
              {loading ? (
                <><Loader2 className="h-4 w-4 animate-spin" /> Đang lưu...</>
              ) : (
                <><Save className="h-4 w-4" /> {form.published ? 'Xuất bản bài viết' : 'Lưu bài viết'}</>
              )}
            </button>
          </div>
        </div>
      </form>
    </div>
  )
}
